/**
 * Wrappers over Orval's generated orders client.
 *
 * `./orders/orders.ts` (regenerated by Orval) is the source of truth for HTTP +
 * types. These wrappers wire React Query around Orval's async client functions
 * (`getOrders`, `postOrders`, …) and unwrap the `{data,status,headers}` envelope
 * so consumers can treat `result.data` as the response body directly.
 */
import {
  useMutation,
  useQuery,
  useQueryClient,
  type UseMutationOptions,
  type UseQueryOptions,
} from "@tanstack/react-query";
import type { ApiHttpError, OrvalResponse } from "../mutator";
import {
  getOrders,
  getOrdersId,
  patchOrdersIdStatus,
  postOrders,
} from "./orders/orders";
import type {
  CreateOrderInput,
  GetOrdersParams,
  OrderWithItems,
  UpdateOrderStatusInput,
} from "./schemas/index";

export type ListOrdersParams = GetOrdersParams;

export const orderKeys = {
  all: ["orders"] as const,
  lists: () => [...orderKeys.all, "list"] as const,
  list: (params?: ListOrdersParams) => [...orderKeys.lists(), params ?? {}] as const,
  details: () => [...orderKeys.all, "detail"] as const,
  detail: (id: number) => [...orderKeys.details(), id] as const,
};

type QueryOpts<T> = { query?: Partial<UseQueryOptions<T, ApiHttpError>> };
type MutationOpts<TData, TVars> = {
  mutation?: Partial<UseMutationOptions<TData, ApiHttpError, TVars>>;
};

async function unwrap<T>(p: Promise<unknown>): Promise<T> {
  return ((await p) as OrvalResponse<T>).data;
}

export function useListOrders(params?: ListOrdersParams, options?: QueryOpts<OrderWithItems[]>) {
  return useQuery<OrderWithItems[], ApiHttpError>({
    queryKey: orderKeys.list(params),
    queryFn: ({ signal }) => unwrap<OrderWithItems[]>(getOrders(params, { signal })),
    ...options?.query,
  });
}

export function useGetOrder(id: number, options?: QueryOpts<OrderWithItems>) {
  return useQuery<OrderWithItems, ApiHttpError>({
    queryKey: orderKeys.detail(id),
    queryFn: ({ signal }) => unwrap<OrderWithItems>(getOrdersId(id, { signal })),
    enabled: Number.isFinite(id) && id > 0,
    ...options?.query,
  });
}

export function useCreateOrder(options?: MutationOpts<OrderWithItems, CreateOrderInput>) {
  const qc = useQueryClient();
  return useMutation<OrderWithItems, ApiHttpError, CreateOrderInput>({
    mutationFn: (data) => unwrap<OrderWithItems>(postOrders(data)),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: orderKeys.all });
      void qc.invalidateQueries({ queryKey: ["stats"] });
    },
    ...options?.mutation,
  });
}

export function useUpdateOrderStatus(
  options?: MutationOpts<OrderWithItems, { id: number; data: UpdateOrderStatusInput }>
) {
  const qc = useQueryClient();
  return useMutation<OrderWithItems, ApiHttpError, { id: number; data: UpdateOrderStatusInput }>({
    mutationFn: ({ id, data }) =>
      unwrap<OrderWithItems>(patchOrdersIdStatus(id, data)),
    onSuccess: (updated) => {
      void qc.invalidateQueries({ queryKey: orderKeys.lists() });
      qc.setQueryData(orderKeys.detail(updated.id), updated);
      void qc.invalidateQueries({ queryKey: ["stats"] });
    },
    ...options?.mutation,
  });
}

// Re-export raw client functions for callers that want them.
export { getOrders, getOrdersId, postOrders, patchOrdersIdStatus };